","item_rarity_skill_def_ele_max","item_rarity_skill_def_magic_min","item_rarity_skill_def_magic_max","item_rarity_skill_health_min","item_rarity_skill_health_max","item_rarity_skill_res_min","item_rarity_skill_res_max","item_rarity_skill_mov_min","item_rarity_skill_mov_max","item_rarity_skill_mod_min","item_rarity_skill_mod_max","item_rarity_skill_special_min","item_rarity_skill_special_max") VALUES (1,'White',1,1000000000,10,15,1,1,NULL,NULL,NULL,NULL,1,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
