INSERT INTO "dialog" ("dialog_id","dialog_group","dialog_npc_id","dialog_npc_type","dialog_weather","dialog_weather_intensity","dialog_mood","dialog_message","dialog_cooldown","dialog_player_level","dialog_group_size","dialog_crowd_size","dialog_reputation_player","dialog_reputation_region","dialog_reputation_continent","dialog_reputation_global","dialog_timing","dialog_type") VALUES (1,NULL,NULL,NULL,NULL,NULL,NULL,'Hold the blade steady; your stance should not waver.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (2,NULL,NULL,NULL,NULL,NULL,NULL,'Keep your blade up—your enemy won’t wait for you to blink',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (3,NULL,NULL,NULL,NULL,NULL,NULL,'Again. And this time, try not to trip over your own feet.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (4,NULL,NULL,NULL,NULL,NULL,NULL,'Your sword is an extension of your will. If you''re uncertain, so is the strike.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (5,NULL,NULL,NULL,NULL,NULL,NULL,'Parry, don’t flail! You’re fighting, not swimming!',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (6,NULL,NULL,NULL,NULL,NULL,NULL,'Good. Now imagine I’m trying to kill you. Because I am.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (7,NULL,NULL,NULL,NULL,NULL,NULL,'Step into the cut. Backpedaling won’t win a duel.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (8,NULL,NULL,NULL,NULL,NULL,NULL,'Sloppy. If you fought like that in the field, you’d be dead before sunrise.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (9,NULL,NULL,NULL,NULL,NULL,NULL,'Nice form—but don’t admire it. Kill, then think.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (10,NULL,NULL,NULL,NULL,NULL,NULL,'The blade doesn’t care how tired you are. Neither do I.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (11,NULL,NULL,NULL,NULL,NULL,NULL,'Control your breathing. If you can’t breathe, you can’t fight.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (12,NULL,NULL,NULL,NULL,NULL,NULL,'Use your hips. That little twig you call an arm won’t carry the blow.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (13,NULL,NULL,NULL,NULL,NULL,NULL,'You hesitated. That’s how you die with your sword still sheathed.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (14,NULL,NULL,NULL,NULL,NULL,NULL,'Better. You might actually survive a tavern brawl now.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (15,NULL,NULL,NULL,NULL,NULL,NULL,'Hear that ring? That’s the sound of a clean block. Learn it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (16,NULL,NULL,NULL,NULL,NULL,NULL,'Your stance is wrong. Fix it before the ground does it for you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (17,NULL,NULL,NULL,NULL,NULL,NULL,'Pain is a great teacher. But I’m cheaper and less bloody. Listen.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (18,NULL,NULL,NULL,NULL,NULL,NULL,'Swordplay isn’t about strength. It’s about precision and intent.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (19,NULL,NULL,NULL,NULL,NULL,NULL,'You’re fast. Now let’s teach you to be dangerous.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (20,NULL,NULL,NULL,NULL,NULL,NULL,'I’m not impressed yet. Bleed for it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (21,NULL,NULL,NULL,NULL,NULL,NULL,'You want to be a warrior? Then stop dancing and fight!',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (22,NULL,NULL,NULL,NULL,NULL,NULL,'Your sword should always know where it''s going—even if you don’t.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (23,NULL,NULL,NULL,NULL,NULL,NULL,'Timing and distance. You master those, you survive. Miss them, you die.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (24,NULL,NULL,NULL,NULL,NULL,NULL,'You strike where it hurts, not where it looks cool.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (25,NULL,NULL,NULL,NULL,NULL,NULL,'Every move you make tells your opponent a story. Stop giving them spoilers.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (26,NULL,NULL,NULL,NULL,NULL,NULL,'Control the centerline, and you control the fight.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (27,NULL,NULL,NULL,NULL,NULL,NULL,'That was better. You might just make it to the end of the week.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (28,NULL,NULL,NULL,NULL,NULL,NULL,'Good—now do it again, without luck holding your hand this time.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (29,NULL,NULL,NULL,NULL,NULL,NULL,'You’re tired? Excellent. That’s when real training begins.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (30,NULL,NULL,NULL,NULL,NULL,NULL,'The only thing worse than your technique is your attitude. Fix both.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (31,NULL,NULL,NULL,NULL,NULL,NULL,'Remember: dead men don’t get to explain why they almost blocked it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (32,NULL,NULL,NULL,NULL,NULL,NULL,'Wow. I’ve seen soup stirred with more aggression than that swing.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (33,NULL,NULL,NULL,NULL,NULL,NULL,'Were you aiming for me or the spirit realm? Because you missed both.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (34,NULL,NULL,NULL,NULL,NULL,NULL,'Your blade’s sharp. Pity the same can’t be said for you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (35,NULL,NULL,NULL,NULL,NULL,NULL,'I’ve met scarecrows with better posture and more fighting spirit.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (36,NULL,NULL,NULL,NULL,NULL,NULL,'Let me know when you’re done warming up so we can start training for real.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (37,NULL,NULL,NULL,NULL,NULL,NULL,'If I wanted someone to flail uselessly, I’d hire a drunken juggler.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (38,NULL,NULL,NULL,NULL,NULL,NULL,'The only thing you''re killing is my patience.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (39,NULL,NULL,NULL,NULL,NULL,NULL,'Did someone teach you that, or did you invent it to embarrass yourself?',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (40,NULL,NULL,NULL,NULL,NULL,NULL,'I’ve seen corpses move with more intent than you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (41,NULL,NULL,NULL,NULL,NULL,NULL,'You fight like you’re hoping your opponent feels bad for you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (42,NULL,NULL,NULL,NULL,NULL,NULL,'Your feet are your foundation. Lose balance, and your blade means nothing.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (43,NULL,NULL,NULL,NULL,NULL,NULL,'Don’t cross your feet—unless you’re trying to get stabbed artistically.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (44,NULL,NULL,NULL,NULL,NULL,NULL,'Step first, strike second. Your blade should follow your weight.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (45,NULL,NULL,NULL,NULL,NULL,NULL,'Stay light on your toes. Heavy feet make slow fighters.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (46,NULL,NULL,NULL,NULL,NULL,NULL,'Don’t meet force with force—redirect it. Let their strength defeat itself.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (47,NULL,NULL,NULL,NULL,NULL,NULL,'A block isn’t just protection. It’s preparation for your counter.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (48,NULL,NULL,NULL,NULL,NULL,NULL,'Keep your guard near your center. Wide swings leave your ribs wide open.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (49,NULL,NULL,NULL,NULL,NULL,NULL,'The moment you block out of fear, you’ve already lost control of the fight.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (50,NULL,NULL,NULL,NULL,NULL,NULL,'Your blade should whisper before it screams—precise, then powerful.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (51,NULL,NULL,NULL,NULL,NULL,NULL,'Cut through the line, not around it. Direct paths win fights.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (52,NULL,NULL,NULL,NULL,NULL,NULL,'Every strike should have purpose. Don’t waste motion showing off.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (53,NULL,NULL,NULL,NULL,NULL,NULL,'A thrust is faster than a swing. Use it when you don’t have time to miss.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (54,NULL,NULL,NULL,NULL,NULL,NULL,'Shoulders down, spine straight. A tense stance is a broken one.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (55,NULL,NULL,NULL,NULL,NULL,NULL,'Your sword hand leads, but your off hand keeps you alive.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (56,NULL,NULL,NULL,NULL,NULL,NULL,'Keep your elbows in. Out wide, they’re just targets.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (57,NULL,NULL,NULL,NULL,NULL,NULL,'Don’t watch their sword—watch their eyes and hips. That’s where the next move comes from.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (58,NULL,NULL,NULL,NULL,NULL,NULL,'Control the tempo. If they’re reacting, they’re not attacking.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (59,NULL,NULL,NULL,NULL,NULL,NULL,'Fights are won before they start—by watching, thinking, and knowing your opponent.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (60,NULL,NULL,NULL,NULL,NULL,NULL,'Fear makes you freeze. Focus makes you fight.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (61,NULL,NULL,NULL,NULL,NULL,NULL,'Discipline isn’t about being perfect. It’s about choosing to stay calm when you want to panic.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (62,NULL,NULL,NULL,NULL,NULL,NULL,'Keep your feet grounded; balance is everything.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (63,NULL,NULL,NULL,NULL,NULL,NULL,'Your grip is correct, now focus on the angle of the cut.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (64,NULL,NULL,NULL,NULL,NULL,NULL,'Neutral minds lead to steady swords.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (65,NULL,NULL,NULL,NULL,NULL,NULL,'Do not overthink, just let the blade move.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (66,NULL,NULL,NULL,NULL,NULL,NULL,'Observe the stance before attempting your strike.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (67,NULL,NULL,NULL,NULL,NULL,NULL,'A sword is only as sharp as the hand that wields it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (68,NULL,NULL,NULL,NULL,NULL,NULL,'Do not rush; steady training yields steady progress.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (69,NULL,NULL,NULL,NULL,NULL,NULL,'Look directly at your opponent, not at their weapon.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (70,NULL,NULL,NULL,NULL,NULL,NULL,'The sword does not judge, it only obeys.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (71,NULL,NULL,NULL,NULL,NULL,NULL,'Too many mistakes… focus, or the sword will punish you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (72,NULL,NULL,NULL,NULL,NULL,NULL,'The edge of your blade trembles like your mind.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (73,NULL,NULL,NULL,NULL,NULL,NULL,'Calm yourself before you snap under the weight of training.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (74,NULL,NULL,NULL,NULL,NULL,NULL,'If you stress over perfection, you will achieve nothing.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (75,NULL,NULL,NULL,NULL,NULL,NULL,'Slow down, breathe, and try again.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (76,NULL,NULL,NULL,NULL,NULL,NULL,'Your footwork is faltering because you’re too tense.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (77,NULL,NULL,NULL,NULL,NULL,NULL,'The sword grows heavier the more you stress over it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (78,NULL,NULL,NULL,NULL,NULL,NULL,'Stop clenching your jaw, you will tire faster.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (79,NULL,NULL,NULL,NULL,NULL,NULL,'Stress breaks concentration, concentration breaks swords.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (80,NULL,NULL,NULL,NULL,NULL,NULL,'Ease your shoulders; tension will betray you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (81,NULL,NULL,NULL,NULL,NULL,NULL,'No, no, no! Stop swinging like it’s a broom handle!',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (82,NULL,NULL,NULL,NULL,NULL,NULL,'You’re hacking at the air, not cutting through it.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (83,NULL,NULL,NULL,NULL,NULL,NULL,'Frustration clouds your edge more than rust.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (84,NULL,NULL,NULL,NULL,NULL,NULL,'Again, but without all that wasted movement!',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (85,NULL,NULL,NULL,NULL,NULL,NULL,'Must I repeat myself a hundred times?',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (86,NULL,NULL,NULL,NULL,NULL,NULL,'Your grip is sloppy—fix it or drop the blade.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (87,NULL,NULL,NULL,NULL,NULL,NULL,'I’ve seen children strike cleaner than this.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (88,NULL,NULL,NULL,NULL,NULL,NULL,'That’s not cutting, that’s flailing.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (89,NULL,NULL,NULL,NULL,NULL,NULL,'Control your temper or lose your hand.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (90,NULL,NULL,NULL,NULL,NULL,NULL,'Don’t fight the sword—it’s already fighting you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (91,NULL,NULL,NULL,NULL,NULL,NULL,'Excellent form! You’re learning quickly.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (92,NULL,NULL,NULL,NULL,NULL,NULL,'The rhythm of your cuts is perfect—keep going!',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (93,NULL,NULL,NULL,NULL,NULL,NULL,'A sharp mind makes a sharp cut.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (94,NULL,NULL,NULL,NULL,NULL,NULL,'Your progress fills me with joy.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (95,NULL,NULL,NULL,NULL,NULL,NULL,'Every strike rings like music to my ears.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (96,NULL,NULL,NULL,NULL,NULL,NULL,'Beautiful! That would cleave a bamboo stalk in two.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (97,NULL,NULL,NULL,NULL,NULL,NULL,'A fine cut—you’ve been listening.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (98,NULL,NULL,NULL,NULL,NULL,NULL,'You are beginning to flow with the blade.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (99,NULL,NULL,NULL,NULL,NULL,NULL,'That was worthy of praise—well done.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (100,NULL,NULL,NULL,NULL,NULL,NULL,'A poor cut like that would shame even the dullest sword.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (101,NULL,NULL,NULL,NULL,NULL,NULL,'The sword droops in your hand like your spirit.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (102,NULL,NULL,NULL,NULL,NULL,NULL,'You swing as if carrying grief on your shoulders.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (103,NULL,NULL,NULL,NULL,NULL,NULL,'Sadness weighs down the blade more than iron.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (104,NULL,NULL,NULL,NULL,NULL,NULL,'Do not let sorrow drag you from your path.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (105,NULL,NULL,NULL,NULL,NULL,NULL,'Even a broken heart must hold steady steel.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (106,NULL,NULL,NULL,NULL,NULL,NULL,'Your cut lacks life, it is drenched in sorrow.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (107,NULL,NULL,NULL,NULL,NULL,NULL,'I can see sadness in every failed step.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (108,NULL,NULL,NULL,NULL,NULL,NULL,'Let the blade carry your grief away.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (109,NULL,NULL,NULL,NULL,NULL,NULL,'Sorrow can teach, but it cannot lead.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (110,NULL,NULL,NULL,NULL,NULL,NULL,'Of course you improved—I’m the one teaching you.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
 (111,NULL,NULL,NULL,NULL,NULL,NULL,'That was flawless. You honor my teaching.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
