BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "mob_category" (
	"mob_category_id"	INTEGER,
	"mob_category_name"	TEXT UNIQUE,
	PRIMARY KEY("mob_category_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "equipment_slot" (
	"equipment_slot_id"	INTEGER,
	"equipment_slot_name"	TEXT UNIQUE,
	PRIMARY KEY("equipment_slot_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "faq" (
	"faq_id"	INTEGER,
	"faq_order"	INTEGER,
	"faq_milestone"	TEXT,
	"faq_category"	INTEGER,
	"faq_question"	TEXT,
	"faq_answer"	TEXT,
	"faq_datetime"	TEXT,
	PRIMARY KEY("faq_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "tool" (
	"tool_id"	INTEGER,
	"tool_name"	TEXT UNIQUE,
	"tool_rate_type"	INTEGER,
	PRIMARY KEY("tool_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "tool_level" (
	"tool_level_id"	INTEGER,
	"tool_level_name"	TEXT UNIQUE,
	"tool_level_rate"	INTEGER,
	"tool_level_quantity"	INTEGER,
	PRIMARY KEY("tool_level_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "proficiency_brewing" (
	"proficiency_brewing_id"	INTEGER,
