	"proficiency_brewing_factor"	INTEGER,
	"proficiency_brewing_probability"	INTEGER,
	PRIMARY KEY("proficiency_brewing_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "proficiency_forging" (
