	PRIMARY KEY("proficiency_mining_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "proficiency_woodcutting" (
	"proficiency_woodcutting_id"	INTEGER,
	"proficiency_woodcutting_level"	INTEGER UNIQUE,
