);
CREATE TABLE IF NOT EXISTS "proficiency_stealing_threat" (
	"proficiency_stealing_threat_id"	INTEGER,
	"proficiency_stealing_threat_level"	INTEGER UNIQUE,
	"proficiency_stealing_threat_probability_success"	INTEGER,
	"proficiency_stealing_threat_probability_discovery"	INTEGER,
	PRIMARY KEY("proficiency_stealing_threat_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "bad_word_dictionary" (
	"bad_word_dictionary_id"	INTEGER,
	"bad_word_dictionary_word"	TEXT,
	"bad_word_dictonary_language"	TEXT,
	"bad_word_dictionary_level"	INTEGER,
	PRIMARY KEY("bad_word_dictionary_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_message" (
	"log_message_id"	INTEGER,
	"log_message_ref"	INTEGER,
	"log_message_warning_level_automated"	INTEGER,
	"log_message_warning_level_manual"	INTEGER,
	"log_message_review_action"	INTEGER,
	"log_message_reviewer1"	INTEGER,
	"log_message_reviewer2"	INTEGER,
	"log_message_reporter"	INTEGER,
	FOREIGN KEY("log_message_ref") REFERENCES "chat_message"("chat_message_id"),
	PRIMARY KEY("log_message_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_monster_fight" (
	"log_monster_fight"	INTEGER
);
CREATE TABLE IF NOT EXISTS "log_play_time" (
	"log_play_time_id"	INTEGER,
	"log_play_time_start"	INTEGER,
	"log_play_time_end"	INTEGER,
	"log_play_time_character"	INTEGER,
	PRIMARY KEY("log_play_time_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_gold_transaction" (
	"log_gold_transaction_id"	INTEGER,
	"log_gold_transaction_origin_mob_type"	INTEGER,
	"log_gold_transaction_origin_player"	INTEGER,
	"log_gold_transaction_origin_mob"	INTEGER,
	"log_gold_transaction_time"	INTEGER,
	"log_gold_transaction_sign"	INTEGER,
	"log_gold_transaction_location_x"	REAL,
	"log_gold_transaction_location_y"	REAL,
	"log_gold_transaction_location_z"	REAL,
	"log_gold_transaction_area"	INTEGER,
	PRIMARY KEY("log_gold_transaction_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_item_transaction" (
	"log_item_transaction_id"	INTEGER,
	"log_item_transaction_origin_mob_type"	INTEGER,
	"log_item_transaction_origin_player"	INTEGER,
	"log_item_transaction_time"	INTEGER,
	"log_item_transaction_sign"	INTEGER,
	"log_item_transaction_location_x"	REAL,
	"log_item_transaction_location_y"	REAL,
	"log_item_transaction_location_z"	REAL,
	"log_item_transaction_area"	INTEGER,
	PRIMARY KEY("log_item_transaction_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "name_type" (
	"name_type_id"	INTEGER,
	"name_type_description"	TEXT UNIQUE,
	PRIMARY KEY("name_type_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "name" (
	"name_id"	INTEGER,
	"name_name"	TEXT UNIQUE,
	"name_name_alt"	TEXT UNIQUE,
	"name_goodness"	INTEGER,
	"name_type"	INTEGER,
	"name_sex"	INTEGER,
	"name_reference"	TEXT,
	"name_description"	TEXT,
	PRIMARY KEY("name_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "skill_attribute" (
	"skill_attribute_id"	INTEGER,
	"skill_attribute_name"	TEXT UNIQUE,
	"skill_attribute_short"	TEXT,
	"skill_attribute_inherit"	INTEGER,
	FOREIGN KEY("skill_attribute_inherit") REFERENCES "skill_attribute"("skill_attribute_id"),
	PRIMARY KEY("skill_attribute_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "skill_modifier" (
	"skill_modifier_id"	INTEGER,
	"skill_modifier_name"	TEXT UNIQUE,
	"skill_modifier_description"	TEXT,
	PRIMARY KEY("skill_modifier_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "chat_message" (
	"chat_message_id"	INTEGER,
	"chat_message_type"	INTEGER,
	"chat_message_time"	INTEGER,
	"chat_message_to"	INTEGER,
	"chat_message_content"	TEXT,
	"chat_message_language"	TEXT,
	"chat_message_character"	INTEGER,
	"chat_message_server"	INTEGER,
	"chat_message_location"	INTEGER,
	PRIMARY KEY("chat_message_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_player_text" (
	"log_player_text_id"	INTEGER,
	"log_player_text_player"	INTEGER,
	"log_player_text_text"	TEXT,
	"log_player_text_type"	INTEGER,
	PRIMARY KEY("log_player_text_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_snapshot" (
	"log_snapshot_id"	INTEGER,
	"log_snapshot_location_x"	REAL,
	"log_snapshot_location_y"	REAL,
	"log_snapshot_location_z"	REAL,
	"log_snapshot_orientation_x"	REAL,
	"log_snapshot_orientation_y"	REAL,
	"log_snapshot_area"	INTEGER,
	"log_snapshot_xp"	INTEGER,
	"log_snapshot_gold"	INTEGER,
	"log_snapshot_action"	INTEGER,
	"log_snapshot_character"	INTEGER,
	PRIMARY KEY("log_snapshot_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "log_auth" (
	"log_auth_id"	INTEGER,
	"log_auth_time"	INTEGER,
	"log_auth_status"	INTEGER,
	"log_auth_account"	INTEGER,
	"log_auth_end"	INTEGER,
	"log_auth_hardware"	TEXT,
	"log_auth_ip"	TEXT,
	"log_auth_origin"	TEXT,
	FOREIGN KEY("log_auth_account") REFERENCES "account"("account_id"),
	PRIMARY KEY("log_auth_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "mob" (
	"mob_id"	INTEGER,
	"mob_name"	TEXT UNIQUE,
	"mob_category"	INTEGER,
	"mob_note"	TEXT,
	FOREIGN KEY("mob_category") REFERENCES "mob_category"("mob_category_id"),
	PRIMARY KEY("mob_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "npc_text_type" (
	"npc_text_type_id"	INTEGER,
	"npc_text_type_name"	TEXT UNIQUE,
	PRIMARY KEY("npc_text_type_id" AUTOINCREMENT)
);
