	"npc_text_condition_id"	INTEGER,
	"npc_text_condition_desc"	TEXT,
	PRIMARY KEY("npc_text_condition_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "npc_text_state" (
	"npc_text_state_id"	INTEGER,
	"npc_text_state_desc"	TEXT UNIQUE,
	PRIMARY KEY("npc_text_state_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "npc_text" (
	"npc_text_id"	INTEGER,
	"npc_text_type"	INTEGER,
	"npc_text_content"	TEXT,
	"npc_text_npc"	INTEGER,
	"npc_text_state"	INTEGER,
	"npc_text_cond1"	INTEGER,
	"npc_text_counter"	INTEGER,
	"npc_text_limit"	INTEGER,
	FOREIGN KEY("npc_text_cond1") REFERENCES "npc_text_condition"("npc_text_condition_id"),
	FOREIGN KEY("npc_text_state") REFERENCES "npc_text_state"("npc_text_state_id"),
	PRIMARY KEY("npc_text_id" AUTOINCREMENT),
	FOREIGN KEY("npc_text_type") REFERENCES "npc_text_type"("npc_text_type_id")
);
