	FOREIGN KEY("achievement_type_score3_reward") REFERENCES "loot_table"("loot_table_id"),
	FOREIGN KEY("achievement_type_score1_reward") REFERENCES "loot_table"("loot_table_id")
);
CREATE TABLE IF NOT EXISTS "mob_loot_table" (
	"mob_loot_table_id"	INTEGER,
	"mob_loot_table_mob"	INTEGER,
	"mob_loot_table_mob_level"	INTEGER,
	"mob_loot_table_table"	INTEGER,
	PRIMARY KEY("mob_loot_table_id" AUTOINCREMENT),
	FOREIGN KEY("mob_loot_table_table") REFERENCES "loot_table"("loot_table_id"),
	FOREIGN KEY("mob_loot_table_mob") REFERENCES "mob"("mob_id")
);
CREATE TABLE IF NOT EXISTS "boat_type" (
	"boat_type_id"	INTEGER,
	"boat_type_name"	TEXT,
	"boat_type_size"	INTEGER,
	"boat_type_speed"	INTEGER,
	"boat_type_armor"	INTEGER,
	"boat_type_turn_rate"	REAL,
	"boat_type_weartear"	INTEGER,
	"boat_type_gold"	INTEGER,
	PRIMARY KEY("boat_type_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "account_character_reserves" (
	"account_character_reserves_id"	INTEGER,
	"account_character_reserves_name"	TEXT UNIQUE,
	"account_character_reserves_comment"	TEXT,
	PRIMARY KEY("account_character_reserves_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "l11n" (
	"l11n_id"	TEXT UNIQUE,
	"l11n_name"	TEXT UNIQUE
);
CREATE TABLE IF NOT EXISTS "quest" (
	"quest_id"	INTEGER UNIQUE,
	"quest_reward"	INTEGER,
	"quest_level_min"	INTEGER,
	"quest_level_max"	INTEGER,
	"quest_class"	INTEGER,
	"quest_prerequesit"	INTEGER,
	PRIMARY KEY("quest_id")
);
CREATE TABLE IF NOT EXISTS "character_quest" (
	"character_quest_id"	INTEGER,
	"character_quest_quest"	INTEGER,
	"character_quest_character"	INTEGER,
	"character_quest_state"	BLOB,
	PRIMARY KEY("character_quest_id" AUTOINCREMENT),
	FOREIGN KEY("character_quest_quest") REFERENCES "quest"("quest_id"),
	FOREIGN KEY("character_quest_character") REFERENCES "character"("character_id")
);
CREATE TABLE IF NOT EXISTS "quest_l11n" (
	"quest_l11n_id"	INTEGER,
	"quest_l11n_lang"	TEXT,
	"quest_l11n_title"	TEXT,
	"quest_l11n_description"	TEXT,
	"quest_l11n_quest"	INTEGER,
	PRIMARY KEY("quest_l11n_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "quest_state" (
	"quest_state_id"	INTEGER,
	PRIMARY KEY("quest_state_id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "quest_state_l11n" (
	"quest_state_l11n_id"	INTEGER,
	"quest_state_l11n_title"	TEXT,
	"quest_state_l11n_desc"	TEXT,
	"quest_state_l11n_state"	INTEGER,
	PRIMARY KEY("quest_state_l11n_id" AUTOINCREMENT),
	FOREIGN KEY("quest_state_l11n_state") REFERENCES "quest_state"("quest_state_id")
);


Possible options include:

- One-time purchase
- Collector''s Edition
- Patreon
- UI themes
- Quality-of-life upgrades
- Cosmetic content
- Optional account services

Our goal is to avoid **pay-to-win** mechanics entirely. Any paid features will be designed so they do not provide gameplay advantages.

Because the game is planned as a live service, our monetization strategy may evolve over time to cover operating costs while remaining fair to players.','2024-05-25'),
 (2,NULL,'Development','Monetization','How much do you think the one-time payment will be?','We are currently thinking about $35 to $60.','2024-05-25'),
 (3,NULL,'Development','Monetization','What would you put into the collectors version?','We plan to offer a selection of goodies, such as an art book, a developer book, and merchandise. The exact details will be decided at a much later stage.

However, we will most likely **not** offer any exclusive in-game content (e.g. cosmetics).','2024-05-25'),
 (4,NULL,'Development','Monetization','What benefits will Patreon supporters receive?','They will most likely receive early updates throughout the development of the release version, gain access to mini demos, participate in polls, join sponsor-exclusive developer streams and discussions, and receive access to selected developer documents.','2024-05-25'),
 (5,NULL,'Development','Monetization','What can I understand under UI themes?','We plan to offer different menu and HUD themes for purchase. These are purely cosmetic and provide no gameplay advantages.','2024-05-25'),
 (6,NULL,'Development','Monetization','What kind of quality of life (QOL) mods are you thinking about?','This is a difficult topic. On the one hand, we do not want to offer any "pay-to-win" content and therefore cannot allow mods that provide a significant gameplay advantage. On the other hand, we want to give players a way to support the project through game modifications.

At this stage, we have not yet decided what these mods could look like. Possible examples include advanced shop information, enhanced player statistics (such as zone heat maps), or DPS meters for dungeons and raids. Any such features would be designed to avoid providing a significant gameplay advantage.','2024-05-25'),
 (7,NULL,'Development','Monetization','Which in-game cosmetics will you provide and how will they effect the game?','Our goal is for almost everything visible in the open world—such as items and skins—to be obtainable through quests, achievements, mob drops, and raids. As a result, we will most likely **not** sell player or item skins.

Instead, our focus for purchasable cosmetics will be:

* Additional emotes and gestures
* Additional furniture and decorative items for your in-game house or apartment
* Additional furniture and decorative items for your pet area
* Additional furniture and decorative items for your guild hall
','2024-05-25'),
 (8,NULL,'Development','Monetization','What are the other services you want to charge?','Other services include the following (with current pricing estimates):

* Character name change — USD 5
* Server transfer — USD 15
* Additional character slot — USD 5
','2024-05-25'),
 (9,NULL,'Development','Account','How many character slots do I have by default?','You will start with 5 character slots. Additional slots can be purchased if needed, and existing characters can be deleted at any time to free up space.
','2024-05-25'),
 (10,NULL,'Development','Account','Can I share my account with someone else?','Account sharing is prohibited. Any accounts found to be shared will be subject to a ban.
','2024-05-25'),
 (11,NULL,'Development','Game','How do you plan to prevent bots?','We plan to implement multiple technologies to identify, block, and make botting unfeasible.

### Limiting shop interactions

* Limit the amount of gold that can be traded between players
* Restrict shop interactions (e.g. prices should remain within a reasonable range of market value)
* Limit the number of items that can be listed in a shop at the same time

> Of course, rare items will still command higher prices.

### Tracking and monitoring

* Track the sources of gold and resources
* Monitor chat messages (e.g. trade offers made through chat)

The exact details of our bot detection systems will remain confidential.
','2024-05-25'),
 (12,NULL,'Development','Game','Will there be expansions?','We don’t know yet. The current vision for the game is very large in scope. Ideally, we would release it as a complete experience from the start and then consider expansions afterward. However, it is safe to say that our current vision is comparable in size to many other MMOs *after* years of expansions.
','2024-05-25'),
 (13,NULL,'Development','Game','Will there be ladders?','Yes, we plan to implement multiple ladders, including:

* Level ladder
* Special dungeon ladders
* Raid ladder
* PvP ladders
* Guild ladder
* And more

Some ladders will be further divided into subcategories, such as global rankings, per-server rankings, per character class, and per game mode.
','2024-05-25'),
 (14,NULL,'Development','Seasons','Will there be seasons?','Yes, we plan to introduce new seasons every 6 months.

Each season will feature its own seasonal ladders, while the permanent (persistent) ladders will remain available at all times.
','2024-05-25'),
 (15,NULL,'Development','Seasons','What kind of season content can I expect?','We are currently working on several ideas, including:

* Requiring players to create a new level 1 seasonal character to participate in seasonal ladders
* Introducing extremely large dungeons with their own ladders (based on completion percentage)
* Adding seasonal gameplay mechanics in special dungeons and areas
* Rebalancing items, skills, and stats
* Introducing special open-world mechanics
','2024-05-25'),
 (16,NULL,'Development','Seasons','Can I participate in seasons with my existing character?','Seasons take place on the same servers. Existing characters can participate in seasonal content, but they will not be eligible for seasonal ladders.

Some seasonal content may also become available to existing characters with a delay compared to new seasonal characters. This is intended to prevent spoilers and avoid trivializing the experience for seasonal players.
','2024-05-25'),
 (17,NULL,'Development','Game','Will there be level scaling?','We generally dislike level scaling, as it can diminish the value of previous player progress. As a result, we aim to avoid it wherever possible. However, some special content may still make use of level scaling where necessary.
','2024-05-25'),
 (18,NULL,'Development','Monetization','Will there be a real money shop?','See game monetization for details.','2024-05-25'),
 (19,NULL,'Development','Monetization','Will you consider a subscription for monetization?','We consider this carefully. Some of us still remember the early days when MMOs became popular and relied on subscription fees, which were often too expensive or difficult to justify for our parents. As a result, some players were unable to play the games they wanted at the time.

We want to avoid this situation as much as possible by using a one-time purchase model, which is generally easier to justify from a player’s perspective.
','2024-05-25'),
 (20,NULL,'Development','Monetization','Will you do regional pricing?','There is a high chance that we will implement regional pricing. However, the exact details will depend on the actual costs required to maintain the game per player in different regions.

That said, our goal is to make the game accessible to as many players as possible worldwide.
','2024-05-25'),
 (21,NULL,'Development','Monetization','Will there be a free version?','Most likely no.','2024-05-25'),
 (22,NULL,'Development','Monetization','Will the game be available on steam?','Most likely not at the very beginning, but we plan to make it available on Steam at a later stage.
','2024-05-25'),
 (23,NULL,'Development','Monetization','Will there be an early access version?','Most likely not.

We understand that early access or pre-purchase models can provide additional funding to help cover development costs. However, we also feel that they can unintentionally gatekeep the excitement of a game’s release.

Anyone who has participated in a game’s launch knows it is a special experience even if it is imperfect or rough around the edges that feels very different from joining later. We want as many players as possible to be part of that moment.
','2024-05-25'),
 (24,NULL,'Development','Release','When will the game be released?','We do not have a release date in mind yet, as we are still far away from launch.

However, we do know that we want to release on a Friday or Saturday, so players can fully enjoy the launch experience over the weekend.
','2024-05-25'),
 (25,NULL,'Development','Game','Which game modes are available?','### Game modes

We plan to support multiple game modes:

* Normal
* Hardcore (HC) — if you die, your character remains dead (except in arenas and pet battles)
* Self-Found (SF) — no trading with other players
* Solo (S) — no grouping (including dungeons and raids)

> Hardcore and Self-Found modes can be combined.

Characters can always opt out of restrictive game modes such as HC, S, and SF at any time. However, opting in is only possible during character creation. Once chosen, a HC character will become a Softcore (SC) character upon death and permanently lose its HC status.

---

### Seasons

* Seasons may also be (S)SF and/or HC
* During the first month of a season, trading in Normal and HC modes is only possible between seasonal characters
','2024-05-25'),
 (26,NULL,'Development','Game','What kind of PvP content will be avilable?','* Open-world duels
* Arena battles (solo or group-based)
* Area and city invasions
* Pet battles
* Dedicated PvP zones (optional / under consideration)
','2024-05-25'),
 (27,NULL,'Development','Game','How do you prevent game breaking builds?','We will apply caps to values such as health, damage, and similar stats, based on expected maximum values multiplied by a safety factor that still allows room for players to exceed our initial expectations. This approach helps prevent players from completely trivializing the game through unintended interactions, broken builds, or bugs.

Of course, once such issues are identified, we may also address them through balance patches.

In addition to manual testing, we will simulate and evaluate multiple builds using genetic algorithms during development to help identify overpowered or broken combinations early.
','2024-05-25'),
 (28,NULL,'Development','Tools','Will there be any content outside the game?','Yes, we plan to offer several features that can also be accessed outside of the game:

* Interactive map in the browser
* Access to the in-game shop for trading and viewing your inventory via the browser
* Playable in-game mini-games in the browser
* A build tool for planning and managing structures
* Pet fostering available through the browser
','2024-05-25'),
 (29,NULL,'Development','Game','How will you avoid content spoiling?','Not all map data is downloaded during installation. We only provide map data for hidden areas once they have been discovered in-game.

Of course, a significant amount of content may still be exposed through data mining. However, this approach helps reduce spoilers for some of the larger hidden areas and key discoveries.
','2024-05-25'),
 (30,NULL,'Development','Game','How large is the map?','This depends on how “map size” is defined. For example, it could refer to walkable terrain, areas including water, dungeons, or even seasonal content.

The main playable world will cover approximately 550 square kilometers of mostly land, with some water areas included. This content will be divided across roughly three continents. With an estimated running speed of around 4 to 4.5 meters per second, it would take approximately 100 minutes to traverse a continent lengthwise.

As mentioned previously, the world also contains large hidden areas as well as dungeons that are not part of the regular main map.
','2024-05-25'),
 (31,NULL,'Development','Game','What makes your MMORPG different than others?','The difference compared to other MMORPGs depends on which games you compare it to. Individually, none of these elements may be entirely unique, but in combination they create something that feels new.

* Strong focus on old-school, hardcore gameplay (e.g. ladders across various types of content)
* Seasonal content
* Distinct art style
* Game modes','2024-05-25'),
 (32,NULL,'Development','Feedback','Why don''t you implement what the players want?','1. The player base is not as homogenous as you may belief
2. Usually the vocal player base albite very passionate only represents a small percentage of the total player base
3. General suggestions might be difficult to implement. E.g. expanding the options for hair styles may push the storage above it''s highly optimized implementation limitation requiring changes to the database, network packets, runtime storage and memory navigation.
4. Players may forget or don''t see the full picture of their suggestions and the effects their suggestions have on the game.
5. Some players may have a different vision for the game than we have.','2024-07-25'),
 (33,NULL,'Development','Feedback','Why do some changes take so long until implementation?','1. Maybe the change isn''t as simple as initially thought due to other interactions or underlying technological implementations.
2. We may have a different focus on tasks. We try to squeeze in shot and simple tasks when reasonable but that cannot always be guaranteed.
3. We put a lot of focus on optimization. However, this can make it more difficult **in some** situations to implement certain changes. ','2024-07-25'),
 (34,NULL,'Development','Game','You claim your game is optimized but I still experience bad performance.','Generally speaking, this can happen for several reasons:

1. Your game settings may not be well-suited to your PC hardware. We provide a wide range of settings to help you achieve the best possible experience on your system. If you encounter issues, we recommend using the general presets (Low, Medium, High, etc.) for a simpler configuration. Don’t be afraid to lower your settings—the highest quality options are intended for the newest GPUs or even future hardware.
2. There may be a bug in the game.
3. There may be issues with your drivers (e.g. GPU drivers).
4. In edge cases, resource requirements may spike—for example, when many players are active in close proximity.
','2024-07-25'),
 (35,NULL,'Development','Feedback','Do you read forums and social media content?','Occasionally, yes, but we do not actively monitor it. Using our feedback platform provides better monitoring, moderation, response handling, and integration with our development workflow.
','2024-07-25'),
 (36,NULL,'Development','Development','Which programming languages do you use?','We primarily use C++23 for our game code, though we often also work in a more C-style approach where appropriate. We rely on a small number of modern C++ features as well as the requirements imposed by DirectX, which make the use of a newer standard necessary.

For web development, we primarily use PHP and JavaScript.
','2024-07-26'),
 (37,NULL,'Development','Development','Why don''t you use more modern features from the most recent C++ versions?','1. We believe they often add unnecessary complexity and can make code harder to read.
2. Many of them introduce hidden costs that are not always obvious to developers, despite sometimes being perceived as “zero-cost” abstractions.
','2024-07-26'),
 (38,NULL,'Development','Development','What are some of the more "modern" features you need from C/C++?','The key features we use include:

* Structs without `typedef`
* Anonymous structs/unions
* Less strict member ordering in structs
* Array initialization using `{}`
* `timespec`
* Scoped enums (`enum class`)
* `aligned_alloc`
* Required features and data structures from external libraries such as DirectX
* `alignas`
* Templates, but only when they lead to more optimized builds rather than creating overly generalized implementations that support multiple data types
','2024-07-26'),
 (39,NULL,'Development','Release','How smooth do you expect the release to be?','Real talk: launching live service games is extremely challenging from an engineering perspective. This becomes even more complex when dealing with a wide distribution of servers across multiple regions and, hopefully, thousands of concurrent players.

While simulations and contingency plans can help, the reality is that we would still only assign a small probability of achieving a completely smooth launch within the first 12–24 hours.

That said, we are doing everything we can to achieve the smoothest possible release experience—but we cannot make any guarantees.
','2024-07-29'),
 (40,NULL,'Development','Game','How do you balance the game?','1. We implement hard limits that prevent players from abusing obvious game-breaking bugs.
2. We perform back-of-the-envelope calculations and spreadsheet-based analysis of stat, skill, and item combinations.
3. We have developed a program that simulates billions of character builds in an effort to identify broken builds or significant imbalances between classes and setups.
4. We conduct extensive internal manual testing.

That being said, it is impossible for every class and build to perform equally in all situations. The game is designed to include variety, rather than forcing all classes and builds into a homogeneous balance state. As a result, certain classes will naturally perform better in specific areas than others.
','2024-08-02'),
 (41,NULL,'Development','Game','The game uses a lot of RAM, VRAM, CPU cores.','Yes, this is intentional.

If your PC hardware allows it, we aim to utilize available RAM, VRAM, and CPU resources as efficiently as reasonable to improve performance and overall gameplay experience.

Live calculations are expensive, so we try to compute values once and store them in memory for reuse instead of recalculating them every frame. In most cases, this approach is beneficial for performance.

For some reason, optimization is often judged by peak RAM or VRAM usage alone. However, a much better metric is the FPS a player can achieve on their hardware using appropriate graphics settings for their system specifications.
','2024-08-28'),
 (42,NULL,'Development','Development','How do you optimize the game?','This is a very broad question.

https://gist.github.com/spl1nes/852485489d8823d8456b74520ca23b69','2024-08-28'),
 (43,NULL,'Development','Game','How do you plan to handle end of life for the game?','First of all, discussing end-of-life for a game that is still in development is somewhat difficult, but we understand the question.

At the moment, we are not sure how we will handle this. One option could be to release the server application along with a license for self-hosted servers (which may require powerful hardware). Another option could be to make a single-player offline mode available. Alternatively, we may choose none of these options and simply discontinue the game when it reaches end of life.
','2024-08-30'),
 (44,NULL,'Development','Game','What is your balancing approach? Buffing vs Nerfing.','We are strongly committed to preventing inflation in the game’s economy and overall balance. As a result, we will both buff what we consider underpowered and nerf what is overpowered. Even if a large portion of the player base prefers a buff-focused balancing approach, we believe that approach would eventually lead to balance issues within a few patches, as well as increasingly exaggerated damage, health, and defense values.

However, for seasonal content, we may introduce a form of rotation-based balancing. This would allow us to adjust underused and overused builds over time, giving players more reasons to experiment with different playstyles.
','2024-08-31'),
 (45,NULL,'Development','Game','Will there be character or account bound items?','Yes.

The highest item rarity will always be account-bound. In addition, all real-money-related content will be account-bound as well (e.g. furniture, skins, etc.).
','2024-09-04'),
 (46,NULL,'Development','Game','For how long was the game in development?','Development began in 2024, but this is not necessarily indicative of the total development duration, as the project has been worked on intermittently over the course of several years.
','2024-09-04'),
 (47,NULL,'Development','Development','What file formats do you use?','We primarily use in-house file formats that are translated into binary data.

The main reasons for this approach are:

* Significant file size reduction (for example, .obj files can be reduced by around 70%–75% without any encoding). With simple and fast LZP encoding, this can reach approximately 80%–85% reduction compared to .obj files.
* Extremely fast loading times, since the data is stored in a format that closely matches how it is used at runtime. This minimizes the need for data transformations.
* High flexibility, as the formats are simple and can be easily extended or adapted to our needs.
* No dependency on third-party libraries
','2024-09-04'),
 (48,NULL,'Development','Game','How will you handle difficulty in the game?','We want to create content across multiple difficulty levels. This means that some content may start relatively easy and become progressively more difficult (e.g. in the open world), while other content (such as dungeons and raids) will allow players to choose their difficulty.

However, we want to be very clear: this does not mean that every player will be able to complete all difficulty levels. The purpose of multiple difficulties is to provide appropriate challenges for players with different skill levels and time investment, including the most dedicated players in the top 1%.

Since we can only create and properly balance a limited number of difficulty tiers, there will be natural jumps in difficulty between them.

We understand that some players may strongly dislike this approach and prefer all content to be accessible to everyone. We respectfully disagree. The goal is not universal accessibility of every difficulty, but meaningful challenge and progression for different types of players.
','2024-09-08'),
 (49,NULL,'Development','Game','On which platforms will you release the game','We will launch on PC (Windows) and hope to bring the game to multiple consoles at a later stage. However, this will depend on the success of the PC release.

We may also consider releasing an unofficial Linux version at some point in the future.
','2025-02-23'),
 (50,NULL,'Development','Development','Which compression algorithms do you use?','* Audio = QOA (fast and simple to implement)
* Image = QOI (fast and simple to implement)
* Network = LZP
','2026-01-18');


A beautiful silver tiara lies in an abandoned crypt. Anyone who wears it slowly becomes obsessed with beauty, power, and immortality.

The Truth

The tiara belonged to Queen Elyra, who murdered her rivals and used forbidden magic to preserve her youth. Upon death, her spirit became bound to the crown.

Quest Flow
Villagers ask you to investigate disappearances.
Victims are found wearing flowers and jewelry.
The tiara is discovered.
Choices
Destroy the Tiara
Queen''s ghost manifests.
Boss fight against the Queen and spectral handmaidens.
Curse is broken.

Reward: Blessed relic.

Keep the Tiara
Can be used to charm nobles and gain information.
Corrupts companions over time.
Let Others Wear It
Various NPCs become mini-bosses:
A blacksmith becomes a tyrant.
A priest declares himself king.
A child becomes a dangerous psychic.
Follow-Up Quest

Another cult tries to recreate the tiara as a follow up quest.',1),
 (2,'en','The Ring of Ashes','Premise

You find a wedding ring near a river.

Investigation

A grieving widower claims his wife disappeared.

Clues:

Blood on a dock.
Villagers fear the husband.
Wife''s diary mentions arguments.
Twist

The husband murdered his wife in a fit of jealousy.

Choices
Turn Him In

He is executed.

Let Him Go

He disappears.

Help Cover It Up

He becomes your ally.

Follow-Up Quest

The wife''s ghost returns and starts haunting the village.

Or:

The husband later becomes a serial killer.',2),
 (3,'en','The Ghost Paths','Premise

A ghost lantern reveals glowing footprints only visible at night.

Following the Trail

The ghost leads you to:

Hidden graves.
Burned houses.
A mass grave.
Twist

The villagers asking for the ghost''s destruction are descendants of murderers.

Choices
Kill the Ghost

Village celebrates.

Years later:

More ghosts appear.
The land becomes cursed.
Help the Ghost

You expose the villagers.

Villagers attack.

Ignore Everything

Both sides hate you.

Follow-Up Quest

The ghost reveals an even older evil beneath the village.',3),
 (4,'en','The Crimson Masquerade','Premise

A noble invites you to an extravagant masked ball.

Throughout the evening:

Guests wear identical masks.
Servants disappear.
Music never stops.
Twist

At midnight, the guests begin a demonic summoning.

Choices
Participate

Gain demonic powers.

Holy Knights hunt you.

Leave

The Inquisition suspects your involvement.

Stop the Ritual

Cultists attack.

Follow-Up Quest

One of the guests survives and starts another cult.',4),
 (5,'en','The Final Performance','Premise

A theater troupe arrives in town.

Every play predicts a murder that happens the next day.

Twist

The actors are possessed.

Or:

The playwright is a demon feeding on tragedy.

Choices
Burn the theater.
Save the actors.
Join the troupe.
Follow-Up

The troupe reappears in another city.',5),
 (6,'en','The Poisoned Well','Premise

A village''s water has become poisonous.

Suspects
Witch in the woods.
Local alchemist.
Mine owner.
Twist

The mine owner knowingly dumped alchemical waste.

Choices
Expose Him

Village survives.

Cover It Up

You get paid.

Blame the Witch

She becomes an enemy.

Follow-Up

The poisoned children begin mutating.',6),
 (7,'en','The Assassin''s Backup Plan','Premise

At a noble''s feast you see someone pour powder into a wine barrel.

If You Stop It

The assassins poison the food instead.

If You Stop Both

You fight the hitmen.

If You Fail

The noble dies.

His family blames you.

Follow-Up

The assassins belonged to a secret organization.',7),
 (8,'en','The House of Little Shadows','Premise

Children laugh inside an abandoned mansion.

Inside:

Toys move.
Paintings cry.
